#include<bits/stdc++.h>
using namespace std;
long long edge[105][105];
const int MAXI=0x7fffffff;
int main()
{
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=100;i++){
		for(int j=1;j<=100;j++){
			edge[i][j]=MAXI;
		}
		edge[i][i]=0;
	}
	for(int i=0;i<m;i++){
		long long u,v,w;
		cin>>u>>v>>w;
		edge[u][v]=edge[v][u]=min(edge[u][v],w);
				
	}
	for(int k=1;k<=n;k++){
		for(int s=1;s<=n;s++){
			for(int t=s+1;t<=n;t++){
				if(edge[s][k]!=MAXI&&edge[k][t]!=MAXI){
					edge[s][t]=min(edge[s][t],edge[s][k]+edge[k][t]);
					edge[t][s]=edge[s][t];
					//cout<<k<<" "<<s<<" "<<t<<" "<<edge[s][t]<<endl;
				}
			}
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cout<<edge[i][j]<<" ";
		}
		cout<<endl;
	}
}
